     if (g <= 16) return { ad: "Dolunay (Bedr)", ikon: "🌕", oran: 100 };
     if (g <= 20) return { ad: "Küçülen Bedir", ikon: "🌖", oran: 75 };
     if (g <= 23) return { ad: "Son Dördün", ikon: "🌗", oran: 50 };
